  function searchIndex(index, query, limit){ const ts = terms(query); return index.map(row => ({...row, score:scoreText(row.haystack, ts)})).filter(r => r.score > 0).sort((a,b) => b.score-a.score).slice(0,limit).map(r => r.item); }
  function searchEducation(query, limit=4){ let out = searchIndex(educationIndex, query, limit); if(!out.length) out = education.filter(m => m.id === 'dbt_wise_mind' || m.id === 'adhd_task_paralysis').slice(0, limit); return out; }
