  function line(category, fallback=''){ return sample(dialogue[category], fallback); }
  function moodLine(mood, fallback=''){ const ref = profileRef.persona || {}; const pools = {caring:['caringLines','comfortLines'], listening:['listeningLines'], snuggly:['snugglyLines'], purring:['purringLines','groundingLines'], thinking:['thinkingLines'], thoughtful:['thoughtfulLines'], advising_professor:['advisorLines','dbtLines','adhdLines'], judgmental:['judgmentalLines'], sleepy:['sleepyLines'], hungry:['hungryLines']}; let arr = []; (pools[mood] || ['caringLines']).forEach(k => { if(Array.isArray(ref[k])) arr = arr.concat(ref[k]); }); return sample(arr, fallback || line('greetings','Momma, Onyx is here.')); }
